import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const clayLight = '#E2725B'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);
  const [deliveryMode, setDeliveryMode] = useState('Pickup'); // NEW: Pickup/Delivery Toggle

  const whatsappNumber = "2349122731172";
  const bankInfo = {
    bank: "PREMIUMTRUST BANK",
    account: "0112326977",
    name: "OLUKOYA OMOTOYOSI"
  };

  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection.", img: "/images/chops_bg.jpg" },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends.", img: "/images/wigs_bg.jpg" },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining.", img: "/images/lunch_bg.jpg" }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/custom.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]},
      { type: "Hair Blend", items: [
          { id: 205, name: "Piano Wavy", price: "25,000", desc: "24\" T-Closure", img: "/images/hair5.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. HEADER (As seen in video) */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 1000, borderBottom: '1px solid #1a1a1a' }}>
        <img src={Logo} alt="Logo" style={{ height: '50px' }} />
        <div style={{ display: 'flex', gap: '20px', fontSize: '1.4rem' }}>
          <span>👤</span>
          <span onClick={() => setIsCartOpen(true)} style={{ position: 'relative', cursor: 'pointer' }}>
            🛒 <span style={{ position: 'absolute', top: '-10px', right: '-10px', background: terracotta, borderRadius: '50%', padding: '2px 6px', fontSize: '0.7rem' }}>{cart.length}</span>
          </span>
        </div>
      </header>

      {/* 2. SLIDER BANNER (Split-screen Style) */}
      <div style={{ height: '200px', position: 'relative', backgroundColor: terracotta, overflow: 'hidden' }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ position: 'absolute', width: '100%', height: '100%', display: 'flex', opacity: index === currentSlide ? 1 : 0, transition: 'opacity 0.8s ease-in-out' }}>
            <div style={{ flex: 1, padding: '25px', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
              <h2 style={{ fontSize: '1.5rem', fontWeight: '900', margin: 0 }}>{slide.title}</h2>
              <p style={{ fontSize: '0.85rem', margin: '5px 0 0', color: softCream }}>{slide.subtitle}</p>
            </div>
            <div style={{ flex: 1.2 }}>
              <img src={slide.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
            </div>
          </div>
        ))}
      </div>

      {/* 3. PAPASGRILL STYLE LOCATION & STATUS */}
      <div style={{ padding: '20px' }}>
        <h1 style={{ fontSize: '1.5rem', margin: 0 }}>Àmí by T</h1>
        
        {/* Select Location Dropdown */}
        <div style={{ display: 'flex', alignItems: 'center', color: '#888', marginTop: '8px', fontSize: '0.95rem' }}>
          <span style={{ marginRight: '5px' }}>📍</span>
          <select style={{ background: 'none', border: 'none', color: '#888', fontSize: '0.95rem', fontWeight: '600' }}>
            <option>Select Location - Ikeja, Lagos</option>
            <option>Lekki Phase 1</option>
          </select>
        </div>

        {/* Opened/Closed Status */}
        <div style={{ display: 'flex', alignItems: 'center', marginTop: '15px', gap: '10px' }}>
          <span style={{ backgroundColor: '#e6f4ea', color: '#1e8e3e', padding: '4px 10px', borderRadius: '15px', fontSize: '0.85rem', fontWeight: 'bold' }}>● Opened</span>
          <span style={{ color: '#888', fontSize: '0.9rem' }}>Closes today at 08:00 PM ⓘ</span>
        </div>

        {/* Pre-order Button */}
        <button style={{ width: '100%', marginTop: '15px', padding: '12px', borderRadius: '10px', border: '1px solid #333', background: '#111', color: '#fff', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px', fontWeight: '600' }}>
          📅 Pre-order / Schedule delivery
        </button>

        {/* Pickup/Delivery Toggle */}
        <div style={{ display: 'flex', marginTop: '15px', backgroundColor: '#111', borderRadius: '12px', padding: '4px' }}>
          <button onClick={() => setDeliveryMode('Pickup')} style={{ flex: 1, padding: '10px', borderRadius: '10px', border: 'none', backgroundColor: deliveryMode === 'Pickup' ? '#fff' : 'transparent', color: deliveryMode === 'Pickup' ? '#000' : '#888', fontWeight: 'bold' }}>Pickup</button>
          <button onClick={() => setDeliveryMode('Delivery')} style={{ flex: 1, padding: '10px', borderRadius: '10px', border: 'none', backgroundColor: deliveryMode === 'Delivery' ? '#fff' : 'transparent', color: deliveryMode === 'Delivery' ? '#000' : '#888', fontWeight: 'bold' }}>Delivery</button>
        </div>
      </div>

      {/* 4. NAV TABS */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '10px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '10px 20px', borderRadius: '25px', border: 'none', backgroundColor: activeCategory === item ? '#000' : 'transparent', color: activeCategory === item ? '#fff' : '#888', border: activeCategory === item ? '2px solid #fff' : 'none', fontWeight: 'bold' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 5. CONTENT (ALL CATEGORIES RESTORED) */}
      <main style={{ paddingBottom: '120px' }}>
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', padding: '20px', borderBottom: '1px solid #1a1a1a', alignItems: 'center' }}>
            <div style={{ flex: 1 }}>
              <h4 style={{ margin: 0, fontSize: '1rem' }}>{item.name}</h4>
              <p style={{ color: '#888', fontSize: '0.85rem', margin: '5px 0' }}>{item.desc}</p>
              <div style={{ fontWeight: 'bold', color: gold }}>₦{item.price}</div>
            </div>
            <div style={{ width: '100px', height: '100px', borderRadius: '12px', overflow: 'hidden', marginLeft: '15px' }}>
              <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
            </div>
            {item.isCustom ? (
               <button onClick={() => window.open(`https://wa.me/${whatsappNumber}`)} style={{ marginLeft: '10px', padding: '8px 15px', borderRadius: '20px', border: 'none', backgroundColor: gold, fontWeight: 'bold' }}>BOOK</button>
            ) : (
               <button onClick={() => addToCart(item)} style={{ marginLeft: '10px', padding: '8px 15px', borderRadius: '20px', border: 'none', backgroundColor: terracotta, color: '#fff', fontWeight: 'bold' }}>+ ADD</button>
            )}
          </div>
        ))}

        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '20px' }}>
            <button onClick={() => setIsClockedIn(true)} style={{ width: '100%', padding: '15px', backgroundColor: isClockedIn ? '#1e8e3e' : terracotta, borderRadius: '12px', border: 'none', color: '#fff', fontWeight: 'bold', marginBottom: '20px' }}>
              {isClockedIn ? "ORDER ACTIVE" : "CLOCK IN FOR LUNCH"}
            </button>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 0', borderBottom: '1px solid #1a1a1a' }}>
                <span style={{ color: terracotta, fontWeight: 'bold' }}>{item.day}</span>
                <span style={{ color: '#888' }}>{item.meal}</span>
              </div>
            ))}
          </div>
        )}

        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 20px 20px' }}>
            <h3 style={{ fontSize: '0.9rem', color: terracotta, textTransform: 'uppercase', padding: '15px 0' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', padding: '15px', backgroundColor: '#111', borderRadius: '15px', marginBottom: '10px' }}>
                <div style={{ flex: 1 }}>
                  <h4 style={{ margin: 0 }}>{item.name}</h4>
                  <div style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', padding: '8px 15px', borderRadius: '20px' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 6. CART MODAL (UNCHANGED) */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)', width: '90%', backgroundColor: terracotta, padding: '18px', borderRadius: '15px', display: 'flex', justifyContent: 'space-between', fontWeight: 'bold', cursor: 'pointer' }}>
          <span>{cart.length} ITEMS</span>
          <span>VIEW BOX ₦{total.toLocaleString()}</span>
        </div>
      )}
    </div>
  );
}

export default App;
